import sailpoint.object.Identity;
import sailpoint.object.QueryOptions;
import sailpoint.object.Filter;
import sailpoint.api.ObjectUtil;

List workgroupMembers = new ArrayList();
QueryOptions ops = new QueryOptions();  
Filter f = Filter.eq("workgroup", true);  
ops.addFilter(f);
String workgroupName = null;
Iterator it = context.search (Identity.class, ops, "name");
while (it.hasNext()) 
{ 
workgroupName = (String)(it.next()[0]);
if(workgroupName.equalsIgnoreCase("RSASecondLevelApprovers"))
{
//Get the members of the workgroup  
Identity wrkGrp = context.getObjectByName(Identity.class, workgroupName);
workgroupMembers.add(wrkGrp);
break;
}
}
sailpoint.tools.Util.flushIterator(it);
if(managersso != null) {
workgroupMembers.add(managersso);
}
return workgroupMembers;

import sailpoint.object.*;
import org.apache.log4j.Logger;
