Logger log = Logger.getLogger(loggerClass);

int min = 10;
int max = 50;
int randomNum = (int)(Math.random() * (max - min + 1) + min);
int randomNum_prefix = (int)(Math.random() * (max - min + 1) + min);
String NewID = "250000" + Integer.toString(randomNum);
if(NewID != null){
String requesteeDisplayName = requesteeFullName+" ("+NewID+")";
workflow.put("requesteeDisplayName",requesteeDisplayName);
}
log.error("Workflow_VSNT_Test_Account_Migration: UID before map "+NewID);
workflow.put("NewID",NewID); 
workflow.put("identityName",NewID); 
workflow.put("UserName",NewID); 
return true;

