import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.ObjectRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.Identity;
import org.apache.log4j.Logger;
import org.apache.log4j.Level;

Logger log = Logger.getLogger(loggerClass);

List provPlansList = new ArrayList();

ProvisioningPlan ndiPlan = (ProvisioningPlan)workflow.get("plan");
ProvisioningPlan adPlan = (ProvisioningPlan)workflow.get("planAD");
provPlansList.add(ndiPlan);

if ( null != adPlan ) {
provPlansList.add(adPlan);
}

ProvisioningPlan provPlan = getConsolidatedPlan(provPlansList, NewID);
workflow.put("consolidatedPlan", provPlan);

import java.util.Map;
import java.util.Date;
import java.util.HashMap;
import java.text.DateFormat;
import java.text.SimpleDateFormat;

import sailpoint.object.Custom;
import sailpoint.object.EmailOptions;
import sailpoint.object.EmailTemplate;

import sailpoint.tools.Util;

import org.apache.log4j.Level;
import org.apache.log4j.Logger;

Logger logger = Logger.getLogger(loggerClass); 

EmailTemplate template = null;
if ( Util.nullSafeCaseInsensitiveEq(statuscheck, "Success") ) {
template = context.getObjectByName(EmailTemplate.class, "EmailTemplate_VSNT_Completion_Migration");
} else {
template = context.getObjectByName(EmailTemplate.class, "EmailTemplate_VSNT_Completion_With_Table_Migration");
}
if (template == null) {
log.debug("Test Account Creation: null template");
} else {
EmailOptions options = new EmailOptions();

String notification = null;
String subject = null;
String header = null;
//options.setCc("nbcuniidmsupportteam@nbcuni.com");

DateFormat dateFormat = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss");
Date date = new Date();
String formattedDate = dateFormat.format(date);
Map dataMap = new HashMap();
dataMap.put("formattedDate", formattedDate);

if (statuscheck != null && statuscheck.equalsIgnoreCase("Success")) {
dataMap.put("statusCheck", statuscheck);
options.setTo(requesteeEmail);
options.setCc(managerEmail);

header = "Test Account created for  " + identityFullName;
log.debug("Test Account Creation: header : " + header);
notification = "New Test Account for " + identityFullName + " (" + NewID + ") has been created. This request was submitted by " + requesterFullName + ".";
log.debug("Test Account Creation: notification " + notification);

if (identityRequestId != null) {
subject = identityRequestId + " - ";
}
subject = "notification: " + subject + "New Test Account created for - " + identityFullName;
log.debug("Test Account Creation:  subject : " + subject);
} else {
Custom nbcuemailaddress = context.getObjectByName(Custom.class, "Custom_VSNT_Mail_box_Name");
String nbcumailbox = nbcuemailaddress.get("emailaddress");
options.setTo(nbcumailbox);
header = "Test Account creation failure for " + identityFullName;
log.debug("Test Account Creation: header : " + header);

notification = "While creation of Test Account failure happened.Please check the logs for " + managerFullName + " (" + supervisorid + ").";
log.debug("Test Account Creation: notification " + notification);
if (NDICrerrMsg != null) {
dataMap.put("NDICrerrMsg", NDICrerrMsg);
}
if (ADerrMsg != null) {
dataMap.put("ADerrMsg", ADerrMsg);
}		

log.debug("Test Account Creation:  ActionRequired : " + ActionRequired);
if (identityRequestId != null) {
subject = identityRequestId + " - ";
}
subject = "notification: " + subject + "Test Account Creation Failure notification - " + NewID;
log.debug("Test Account Creation: subject : " + subject);

if ( Util.isNotNullOrEmpty(firstname) ) {
dataMap.put("firstName", firstname);
}
if ( Util.isNotNullOrEmpty(lastname) ) {
dataMap.put("lastName", lastname);
}
if ( Util.isNotNullOrEmpty(NewID) ) {
dataMap.put("NewID", NewID);
}
if (startDate != null) {
dataMap.put("startDate", startDate);
}
if (endDate != null) {
dataMap.put("endDate", endDate);
}
if (chkADRequest != null) {
dataMap.put("chkADRequest", chkADRequest);
}
}

Map args = new HashMap();
args.put("header", header);
args.put("notification", notification);
args.put("subject", subject);
args.put("CCAddress", "");
if (dataMap != null) {
args.put("functionalTestAccountDrupalMailboxMigrationNotifyCompletionDataMap", dataMap);
}
options.setVariables(args);
context.sendEmailNotification(template, options);
}
